<h1 class="h5">Pagos</h1><table class="table table-sm"><thead><tr><th>Empresa</th><th>Monto</th><th>Método</th><th>Estado</th><th>Fecha</th></tr></thead><tbody><?php foreach($pagos as $p): ?><tr><td><?= e($p['empresa']) ?></td><td>$<?= number_format((float)$p['monto'],2) ?> <?= e($p['moneda']) ?></td><td><?= e($p['metodo']) ?></td><td><span class="badge text-bg-light"><?= e($p['estado']) ?></span></td><td><?= e($p['fecha_pago']) ?></td></tr><?php endforeach; ?></tbody></table>
